const body = $json.body ?? {};
const platforms = body.platforms ?? {};

if (body.schemaVersion !== 1) {
  throw new Error('Unsupported Social Deck schema version');
}

if (body.testConnection === true) {
  return [{ json: {
    connectionTest: true,
    response: {
      ok: true,
      type: 'connection-test',
      source: 'n8n',
      receivedAt: new Date().toISOString()
    }
  } }];
}

function parseText(platform, limit) {
  const value = platforms[platform]?.text;
  if (typeof value !== 'string' || value.trim().length === 0) {
    throw new Error(platform + ' text is required');
  }
  if ([...value].length > limit) {
    throw new Error(platform + ' text exceeds ' + limit + ' characters');
  }
  return value;
}

function utf8Index(text, utf16Index) {
  const value = text.slice(0, utf16Index);
  if (typeof TextEncoder !== 'undefined') {
    return new TextEncoder().encode(value).byteLength;
  }
  if (typeof Buffer !== 'undefined') {
    return Buffer.byteLength(value, 'utf8');
  }
  return unescape(encodeURIComponent(value)).length;
}

function parseUrlFacets(text) {
  const facets = [];
  const urlPattern = /https?:\/\/[^\s<>"']+/g;
  let match;

  while ((match = urlPattern.exec(text)) !== null) {
    const uri = match[0].replace(/[),.!?;:]+$/g, '');
    if (!/^https?:\/\//.test(uri)) {
      continue;
    }

    const start = match.index;
    const end = start + uri.length;
    facets.push({
      index: {
        byteStart: utf8Index(text, start),
        byteEnd: utf8Index(text, end)
      },
      features: [
        {
          $type: 'app.bsky.richtext.facet#link',
          uri
        }
      ]
    });
  }

  return facets;
}

const text = parseText('bluesky', 300);
return [{ json: {
  connectionTest: false,
  source: body.source ?? {},
  requestedAt: body.requestedAt ?? null,
  bluesky: {
    text,
    facets: parseUrlFacets(text)
  }
} }];

