={{ JSON.stringify((() => {
  const bluesky = $('Validate request').first().json.bluesky;
  const record = {
    '$type': 'app.bsky.feed.post',
    text: bluesky.text,
    createdAt: $now.toUTC().toISO(),
    langs: ['en']
  };
  if (Array.isArray(bluesky.facets) && bluesky.facets.length > 0) {
    record.facets = bluesky.facets;
  }
  return {
    repo: $json.did,
    collection: 'app.bsky.feed.post',
    record
  };
})()) }}

